CommandRegistrationCallback.EVENT.register((dispatcher, registryAccess, environment) -> {
    dispatcher.register(literal("hello").executes(context -> {
        context.getSource().sendFeedback(() -> Text.literal("Hello World!"), false);
        return 1;
    }));
});

dispatcher.register(literal("giveitem")
    .then(argument("target", EntityArgumentType.player())
        .then(argument("item", ItemStackArgumentType.itemStack())
            .executes(context -> {
                ServerPlayerEntity target = EntityArgumentType.getPlayer(context, "target");
                ItemStack stack = ItemStackArgumentType.getItemStackArgument(context, "item").createStack(1, false);
                target.getInventory().insertStack(stack);
                return 1;
            }))));

dispatcher.register(literal("setvalue")
    .then(argument("value", IntegerArgumentType.integer(1, 100))
        .executes(context -> {
            int value = IntegerArgumentType.getInteger(context, "value");
            context.getSource().sendFeedback(() -> Text.literal("设置值为: " + value), false);
            return 1;
        })));

dispatcher.register(literal("admin")
    .requires(source -> source.hasPermissionLevel(2))
    .executes(context -> {
        context.getSource().sendFeedback(() -> Text.literal("管理员命令"), true);
        return 1;
    }));

dispatcher.register(literal("mod")
    .then(literal("reload")
        .executes(context -> {
            // 重新加载逻辑
            return 1;
        }))
    .then(literal("status")
        .executes(context -> {
            // 状态查询逻辑
            return 1;
        })));

dispatcher.register(literal("givecustom")
    .then(argument("item", StringArgumentType.word())
        .suggests((context, builder) -> {
            builder.suggest("sword");
            builder.suggest("pickaxe");
            builder.suggest("axe");
            return builder.buildFuture();
        })
        .executes(context -> {
            String item = StringArgumentType.getString(context, "item");
            return 1;
        })));

dispatcher.register(literal("help")
    .executes(context -> {
        context.getSource().sendFeedback(() -> Text.literal("可用命令:"), false);
        context.getSource().sendFeedback(() -> Text.literal("/hello - 打招呼"), false);
        context.getSource().sendFeedback(() -> Text.literal("/giveitem <玩家> <物品> - 给予物品"), false);
        return 1;
    }));
